css:
:root {
  /* Botanical Organic Serif Palette */
  --background: #F9F8F4;
  --foreground: #2D3A31;

  --card: #FFFFFF;
  --card-foreground: #2D3A31;
  --popover: #FFFFFF;
  --popover-foreground: #2D3A31;

  --primary: #8C9A84;
  --primary-foreground: #FFFFFF;
  --secondary: #DCCFC2;
  --secondary-foreground: #2D3A31;

  --muted: #F2F0EB;
  --muted-foreground: #8C9A84;

  --accent: #C27B66;
  --accent-foreground: #FFFFFF;

  --destructive: #b91c1c;
  --destructive-foreground: #FFFFFF;
  --border: #E6E2DA;
  --input: #E6E2DA;
  --ring: #8C9A84;

  --chart-1: #8C9A84;
  --chart-2: #DCCFC2;
  --chart-3: #C27B66;
  --chart-4: #2D3A31;
  --chart-5: #E6E2DA;

  --radius: 1.5rem; /* rounded-3xl default for botanical */

  --sidebar: #F9F8F4;
  --sidebar-foreground: #2D3A31;
  --sidebar-primary: #8C9A84;
  --sidebar-primary-foreground: #FFFFFF;
  --sidebar-accent: #DCCFC2;
  --sidebar-accent-foreground: #2D3A31;
  --sidebar-border: #E6E2DA;
  --sidebar-ring: #8C9A84;
}

.dark {
  --background: oklch(0.12 0.01 280);
  --foreground: oklch(0.95 0.01 90);
  --card: oklch(0.18 0.01 280);
  --card-foreground: oklch(0.95 0.01 90);
  --popover: oklch(0.18 0.01 280);
  --popover-foreground: oklch(0.95 0.01 90);
  --primary: oklch(0.65 0.2 280);
  --primary-foreground: oklch(0.12 0.01 280);
  --secondary: oklch(0.5 0.15 200);
  --secondary-foreground: oklch(0.95 0.01 90);
  --muted: oklch(0.3 0.01 280);
  --muted-foreground: oklch(0.7 0.01 90);
  --accent: oklch(0.75 0.2 40);
  --accent-foreground: oklch(0.12 0.01 280);
  --destructive: oklch(0.577 0.245 27.325);
  --destructive-foreground: oklch(0.95 0.01 90);
  --border: oklch(0.25 0.01 280);
  --input: oklch(0.25 0.01 280);
  --ring: oklch(0.65 0.2 280 / 0.5);
  --chart-1: oklch(0.65 0.2 280);
  --chart-2: oklch(0.5 0.15 200);
  --chart-3: oklch(0.75 0.2 40);
  --chart-4: oklch(0.45 0.15 160);
  --chart-5: oklch(0.7 0.18 320);
  --sidebar: oklch(0.15 0.01 280);
  --sidebar-foreground: oklch(0.95 0.01 90);
  --sidebar-primary: oklch(0.65 0.2 280);
  --sidebar-primary-foreground: oklch(0.12 0.01 280);
  --sidebar-accent: oklch(0.75 0.2 40);
  --sidebar-accent-foreground: oklch(0.12 0.01 280);
  --sidebar-border: oklch(0.25 0.01 280);
  --sidebar-ring: oklch(0.65 0.2 280 / 0.5);
}
